   375→    private Executor onEnd(Executor executor) {
   376→        final Flow flow = executor.getFlow();
   377→
   378→        Execution newExecution = executor.getExecution()
   379→            .withState(executor.getExecution().guessFinalState(flow));
   380→
   381→        if (flow.getOutputs() != null) {
   382→            RunContext runContext = runContextFactory.of(executor.getFlow(), executor.getExecution());
   383→            try {
   384→                Map<String, Object> outputs = flow.getOutputs()
   385→                    .stream()
   386→                    .collect(HashMap::new, (map, entry) -> map.put(entry.getId(), entry.getValue()), Map::putAll);
   387→                outputs = runContext.render(outputs);
   388→                outputs = flowInputOutput.typedOutputs(flow, executor.getExecution(), outputs);
   389→                newExecution = newExecution.withOutputs(outputs);
   390→            } catch (Exception e) {
   391→                logService.logExecution(
   392→                    executor.getExecution(),
   393→                    Level.ERROR,
   394→                    "Failed to render output values",
   395→                    e
   396→                );
   397→                runContext.logger().error("Failed to render output values: {}", e.getMessage(), e);
   398→                newExecution = newExecution.withState(State.Type.FAILED);
   399→            }
   400→        }
   401→
   402→        logService.logExecution(
   403→            newExecution,
   404→            Level.INFO,
   405→            "Flow completed with state {} in {}",
   406→            newExecution.getState().getCurrent(),
   407→            newExecution.getState().humanDuration()
   408→        );
   409→
   410→        if (log.isTraceEnabled()) {
   411→            log.trace(newExecution.toString(true));
   412→        }
   413→
   414→        metricRegistry
   415→            .counter(MetricRegistry.METRIC_EXECUTOR_EXECUTION_END_COUNT, MetricRegistry.METRIC_EXECUTOR_EXECUTION_END_COUNT_DESCRIPTION, metricRegistry.tags(newExecution))
   416→            .increment();
   417→
   418→        metricRegistry
   419→            .timer(MetricRegistry.METRIC_EXECUTOR_EXECUTION_DURATION, MetricRegistry.METRIC_EXECUTOR_EXECUTION_DURATION_DESCRIPTION, metricRegistry.tags(newExecution))
   420→            .record(newExecution.getState().getDuration());
   421→
   422→        return executor.withExecution(newExecution, "onEnd");
   423→    }
