   444→    private Executor handleChildNext(Executor executor) throws InternalException {
   445→        if (executor.getExecution().getTaskRunList() == null) {
   446→            return executor;
   447→        }
   448→
   449→        List<TaskRun> running = executor.getExecution()
   450→            .getTaskRunList()
   451→            .stream()
   452→            .filter(taskRun -> taskRun.getState().isRunning())
   453→            .toList();
   454→
   455→        // Remove functional style to avoid (class io.kestra.core.exceptions.IllegalVariableEvaluationException cannot be cast to class java.lang.RuntimeException'
   456→        ArrayList<TaskRun> result = new ArrayList<>();
   457→
   458→        for (TaskRun taskRun : running) {
   459→            result.addAll(this.childNextsTaskRun(executor, taskRun));
   460→        }
   461→
   462→        if (result.isEmpty()) {
   463→            return executor;
   464→        }
   465→
   466→        return executor.withTaskRun(result, "handleChildNext");
   467→    }
