   618→    private AbstractRetry searchForParentRetry(TaskRun taskRun, Executor executor) {
   619→        // search in all parents, recursively
   620→        if (taskRun.getParentTaskRunId() != null) {
   621→            String taskId = taskRun.getTaskId();
   622→            Task parentTask;
   623→            do {
   624→                parentTask = executor.getFlow().findParentTasksByTaskId(taskId);
   625→                if (parentTask != null) {
   626→                    taskId = parentTask.getId();
   627→                }
   628→            } while (parentTask != null && parentTask.getRetry() == null);
   629→
   630→            if (parentTask != null) {
   631→                return parentTask.getRetry();
   632→            }
   633→        }
   634→
   635→        return null;
   636→    }
