   638→    private Executor handlePausedDelay(Executor executor, List<WorkerTaskResult> workerTaskResults) throws InternalException {
   639→        if (workerTaskResults
   640→            .stream()
   641→            .noneMatch(workerTaskResult -> workerTaskResult.getTaskRun().getState().getCurrent() == State.Type.PAUSED)) {
   642→            return executor;
   643→        }
   644→
   645→        List<ExecutionDelay> list = workerTaskResults
   646→            .stream()
   647→            .filter(workerTaskResult -> workerTaskResult.getTaskRun().getState().getCurrent() == State.Type.PAUSED)
   648→            .map(throwFunction(workerTaskResult -> {
   649→                Task task = executor.getFlow().findTaskByTaskId(workerTaskResult.getTaskRun().getTaskId());
   650→
   651→                if (task instanceof Pause pauseTask) {
   652→                    if (pauseTask.getPauseDuration() != null || pauseTask.getTimeout() != null) {
   653→                        RunContext runContext = runContextFactory.of(executor.getFlow(), executor.getExecution());
   654→                        Duration duration = runContext.render(pauseTask.getPauseDuration()).as(Duration.class).orElse(null);
   655→                        Duration timeout = runContext.render(pauseTask.getTimeout()).as(Duration.class).orElse(null);
   656→                        Pause.Behavior behavior  = runContext.render(pauseTask.getBehavior()).as(Pause.Behavior.class).orElse(Pause.Behavior.RESUME);
   657→                        if (duration != null || timeout != null) { // rendering can lead to null, so we must re-check here
   658→                            // if duration is set, we use it, and we use the Pause behavior as a state
   659→                            // if no duration, we use the standard timeout property and use FAILED as the target state
   660→                            return ExecutionDelay.builder()
   661→                                .taskRunId(workerTaskResult.getTaskRun().getId())
   662→                                .executionId(executor.getExecution().getId())
   663→                                .date(workerTaskResult.getTaskRun().getState().maxDate().plus(duration != null ? duration : timeout))
   664→                                .state(duration != null ? behavior.mapToState() : State.Type.fail(pauseTask))
   665→                                .delayType(ExecutionDelay.DelayType.RESUME_FLOW)
   666→                                .build();
   667→                        }
   668→                    }
   669→                }
   670→
   671→                return null;
   672→            }))
   673→            .filter(Objects::nonNull)
   674→            .toList();
   675→
   676→        if (executor.getExecution().getState().getCurrent() != State.Type.PAUSED) {
   677→            return executor
   678→                .withExecution(executor.getExecution().withState(State.Type.PAUSED), "handlePausedDelay")
   679→                .withWorkerTaskDelays(list, "handlePausedDelay");
   680→        }
   681→
   682→        return executor.withWorkerTaskDelays(list, "handlePausedDelay");
   683→    }
