  1036→    private Executor handleExecutionUpdatingTask(final Executor executor) throws InternalException {
  1037→        List<WorkerTaskResult> workerTaskResults = new ArrayList<>();
  1038→
  1039→        executor.getWorkerTasks()
  1040→            .removeIf(workerTask -> {
  1041→                if (!(workerTask.getTask() instanceof ExecutionUpdatableTask)) {
  1042→                    return false;
