  1044→
  1045→                var executionUpdatingTask = (ExecutionUpdatableTask) workerTask.getTask();
  1046→
  1047→                try {
  1048→                    executor.withExecution(
  1049→                        executionUpdatingTask.update(executor.getExecution(), workerTask.getRunContext())
  1050→                            .withTaskRun(workerTask.getTaskRun().withState(State.Type.RUNNING)),
  1051→                        "handleExecutionUpdatingTask.updateExecution"
  1052→                    );
  1053→
  1054→                    var taskState = executionUpdatingTask.resolveState(workerTask.getRunContext(), executor.getExecution()).orElse(State.Type.SUCCESS);
  1055→                    workerTaskResults.add(
  1056→                        WorkerTaskResult.builder()
  1057→                            .taskRun(workerTask.getTaskRun().withAttempts(
  1058→                                        Collections.singletonList(TaskRunAttempt.builder().state(new State().withState(taskState)).build())
  1059→                                    )
  1060→                                    .withState(taskState)
  1061→                            )
  1062→                            .build()
  1063→                    );
  1064→                } catch (Exception e) {
