            if (execution.getTrigger() != null) {
                FlowWithSource flow = executor.getFlow();
                triggerRepository
                    .findByExecution(execution)
                    .ifPresent(trigger -> {
                        this.triggerState.update(executionService.resetExecution(flow, execution, trigger));
                    });
            }

