import io.micronaut.test.extensions.junit5.annotation.MicronautTest;
import jakarta.inject.Inject;
import jakarta.inject.Named;
import org.junit.jupiter.api.Test;
import reactor.core.publisher.Flux;

import java.io.ByteArrayInputStream;
import java.net.URI;
import java.time.Duration;
import java.util.Map;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;

import static io.kestra.core.tenant.TenantService.MAIN_TENANT;
import static org.assertj.core.api.Assertions.assertThat;

@MicronautTest
@JdbcRunnerEnabled
public class ForEachItemAfterExecutionTest {
    static final String TEST_NAMESPACE = "io.kestra.tests.foreach";

    @Inject
    @Named(QueueFactoryInterface.EXECUTION_NAMED)
    private QueueInterface<Execution> executionQueue;

    @Inject
    private StorageInterface storageInterface;

    @Inject
    protected RunnerUtils runnerUtils;

    @Inject
    private FlowInputOutput flowIO;

    @Test
    public void testForEachItemWithAfterExecution() throws Exception {
        // Track the number of subflow executions that complete
        AtomicInteger subflowCompletedCount = new AtomicInteger(0);
        CountDownLatch subflowsCompleted = new CountDownLatch(3); // We'll create 3 items

        Flux<Execution> receive = TestsUtils.receive(executionQueue, either -> {
            Execution execution = either.getLeft();
            if (execution.getFlowId().equals("foreach-subflow-with-afterexecution") &&
                execution.getState().getCurrent().isTerminated()) {
                int count = subflowCompletedCount.incrementAndGet();
                System.out.println("Subflow " + count + " completed with state: " + execution.getState().getCurrent());
                subflowsCompleted.countDown();
            }
        });

        // Create a test file with 3 items
        String testData = "item1\nitem2\nitem3\n";
        URI file = storageInterface.put(MAIN_TENANT, null, URI.create("/file/test.txt"),
            new ByteArrayInputStream(testData.getBytes()));

        // Execute the parent flow
        Map<String, Object> inputs = Map.of("file", file.toString());
        Execution execution = runnerUtils.runOne(MAIN_TENANT, TEST_NAMESPACE, "foreach-parent-with-afterexecution", null,
            (flow, execution1) -> flowIO.readExecutionInputs(flow, execution1, inputs),
            Duration.ofSeconds(60));

        // Wait for all subflows to complete
        assertThat(subflowsCompleted.await(30, TimeUnit.SECONDS))
            .as("All 3 subflows should complete within 30 seconds")
            .isTrue();

        System.out.println("All subflows completed. Parent execution state: " + execution.getState().getCurrent());

        // The parent execution should also be in a terminal state
        assertThat(execution.getState().getCurrent()).isEqualTo(State.Type.SUCCESS);

        // The ForEachItem task should be in SUCCESS state
        assertThat(execution.getTaskRunList()).isNotEmpty();
        var forEachItemTaskRun = execution.getTaskRunList().stream()
            .filter(tr -> tr.getTaskId().equals("each"))
            .findFirst()
            .orElseThrow();
        assertThat(forEachItemTaskRun.getState().getCurrent()).isEqualTo(State.Type.SUCCESS);

        receive.blockLast();
    }
}

