    @SuppressWarnings("unchecked")
    public void forEachItemWithAfterExecution() throws TimeoutException, InterruptedException, URISyntaxException, IOException, QueueException {
        CountDownLatch countDownLatch = new CountDownLatch(3); // We'll create 3 items
        AtomicReference<Execution> triggered = new AtomicReference<>();

        Flux<Execution> receive = TestsUtils.receive(executionQueue, either -> {
            Execution execution = either.getLeft();
            if (execution.getFlowId().equals("foreach-subflow-with-afterexecution") && execution.getState().getCurrent().isTerminated()) {
                triggered.set(execution);
                countDownLatch.countDown();
            }
        });

        // Create a test file with 3 items
        String testData = "item1\nitem2\nitem3\n";
        URI file = storageInterface.put(MAIN_TENANT, null, URI.create("/file/test-afterexec.txt"),
            new java.io.ByteArrayInputStream(testData.getBytes()));

        Map<String, Object> inputs = Map.of("file", file.toString());
        Execution execution = runnerUtils.runOne(MAIN_TENANT, "io.kestra.tests.foreach", "foreach-parent-with-afterexecution", null,
            (flow, execution1) -> flowIO.readExecutionInputs(flow, execution1, inputs),
            Duration.ofSeconds(60));

        // Wait for all subflows to complete
        assertThat(countDownLatch.await(30, TimeUnit.SECONDS))
            .as("All 3 subflows should complete within 30 seconds")
            .isTrue();
        receive.blockLast();

        // assert on the main flow execution
        assertThat(execution.getState().getCurrent())
            .as("Parent execution should be in SUCCESS state")
            .isEqualTo(State.Type.SUCCESS);

        // Find the ForEachItem task run
        var eachTaskRun = execution.getTaskRunList().stream()
            .filter(tr -> tr.getTaskId().equals("each"))
            .findFirst()
            .orElseThrow(() -> new AssertionError("ForEachItem task 'each' should exist"));

        assertThat(eachTaskRun.getState().getCurrent())
            .as("ForEachItem task should be in SUCCESS state")
            .isEqualTo(State.Type.SUCCESS);

        Map<String, Object> outputs = eachTaskRun.getOutputs();
        assertThat(outputs.get("numberOfBatches")).isEqualTo(3);
        assertThat(outputs.get("iterations")).isNotNull();
        Map<String, Integer> iterations = (Map<String, Integer>) outputs.get("iterations");
        assertThat(iterations.get("CREATED")).as("No tasks should be CREATED").isZero();
        assertThat(iterations.get("RUNNING")).as("No tasks should be RUNNING").isZero();
        assertThat(iterations.get("SUCCESS")).as("All 3 tasks should be SUCCESS").isEqualTo(3);

        // assert on the last subflow execution - should have both main task and afterExecution task
        assertThat(triggered.get().getState().getCurrent()).isEqualTo(State.Type.SUCCESS);
        assertThat(triggered.get().getFlowId()).isEqualTo("foreach-subflow-with-afterexecution");
        // Subflow should have 2 task runs: per-item and afterexec
        assertThat(triggered.get().getTaskRunList()).hasSize(2);

        // Verify the after_foreach task also ran
        var afterForEachTask = execution.getTaskRunList().stream()
            .filter(tr -> tr.getTaskId().equals("after_foreach"))
            .findFirst()
            .orElseThrow(() -> new AssertionError("after_foreach task should exist"));
        assertThat(afterForEachTask.getState().getCurrent()).isEqualTo(State.Type.SUCCESS);
    }
}

