            Duration.ofSeconds(60));

        // Wait for all subflows to complete
        assertThat(countDownLatch.await(30, TimeUnit.SECONDS))
            .as("All 3 subflows should complete within 30 seconds")
            .isTrue();
        receive.blockLast();

        // assert on the main flow execution
        assertThat(execution.getState().getCurrent())
            .as("Parent execution should be in SUCCESS state")
            .isEqualTo(State.Type.SUCCESS);

